package com.project.credflow.mapper;

import com.project.credflow.dto.InvoiceDto;
import com.project.credflow.enums.InvoiceStatus; // 1. Import InvoiceStatus
import com.project.credflow.model.Invoice;
import org.springframework.stereotype.Component;

import java.time.LocalDate; // 2. Import LocalDate
import java.time.temporal.ChronoUnit; // 3. Import ChronoUnit

@Component
public class InvoiceMapper {

    public InvoiceDto toInvoiceDto(Invoice invoice) {
        if (invoice == null) {
            return null;
        }

        InvoiceDto dto = new InvoiceDto();
        dto.setInvoiceId(invoice.getInvoiceId());
        dto.setInvoiceNumber(invoice.getInvoiceNumber());
        dto.setAmountDue(invoice.getAmountDue());
        dto.setDueDate(invoice.getDueDate());
        dto.setStatus(invoice.getStatus());

        // --- 4. Calculate overdueDays ---
        Integer days = null; // Default to null
        if (invoice.getStatus() == InvoiceStatus.OVERDUE && invoice.getDueDate() != null) {
            // Use LocalDate.now() which respects the server's timezone implicitly
            long daysBetween = ChronoUnit.DAYS.between(invoice.getDueDate(), LocalDate.now());
            // Ensure days are not negative and cast to Integer
            days = (int) Math.max(0, daysBetween);
        }
        dto.setOverdueDays(days);
        // --- End Calculation ---

        return dto;
    }
}

