    // Helper method to get the current authenticated user securely
    private User getCurrentUser() {
        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
        if (authentication == null || !authentication.isAuthenticated() || !(authentication.getPrincipal() instanceof User)) {
            // This should ideally not happen if the endpoint is secured,
            // but it's a safeguard.
            log.error("AI Tool: Could not retrieve authenticated user from SecurityContext.");
            throw new IllegalStateException("User not authenticated.");
        }
        return (User) authentication.getPrincipal();
    }

    @Tool("Fetches a summary of the current customer's invoices")
    public String getCurrentUserInvoiceSummary() {
        log.info("AI Tool: Executing getCurrentUserInvoiceSummary");
        try {
            User currentUser = getCurrentUser();
            List<InvoiceDto> invoices = customerApiService.getCurrentUserInvoices(currentUser);

            if (invoices == null || invoices.isEmpty()) {
                return "You currently have no invoices on record.";
            }

            long overdueCount = invoices.stream().filter(inv -> "OVERDUE".equals(inv.getStatus().name())).count();
            String overdueMsg = overdueCount > 0 ? String.format(" %d of which are OVERDUE.", overdueCount) : "";

